// Verify /api/directions returns 400 for non-numeric coordinate values
async function testDirectionsNonNumericParams() {
  const res = await fetch('http://localhost:3001/api/directions?lat=abc&lon=def');
  assertEquals(res.status, 400);
  const body = await res.json();
  assertEquals(body.error, true);
  assertEquals(body.message, 'lat and lon query parameters are required');
}
